+fn validate_link_prediction_pairs(gr: &GraphRef<'_>, pairs: &[(String, String)]) -> PyResult<()> {
+    for (u, v) in pairs {
+        if !gr.has_node(u) {
+            return Err(NodeNotFound::new_err(format!("Node {u} not in G.")));
+        }
+        if !gr.has_node(v) {
+            return Err(NodeNotFound::new_err(format!("Node {v} not in G.")));
+        }
+    }
+    Ok(())
+}
